config_yaml:
# P0-M6 G1 stiffness-validity pilot fixture.
# The 20 primitive sequences below were generated once with numpy.default_rng(42)
# and are intentionally frozen here; this config is the measurement fixture.
rope:
  length_m: 1.0
  n_segments: 50
  bend_stiffness: 1.0
  twist_stiffness: 1.0
  friction: 1.0
  radius: 0.005
sim:
  dt: 0.001
  substeps: 5
  rod_damping: 10.0
  rod_angular_damping: 5.0
  initial_settle_steps: 0
  reset_settle_max_steps: 5000
  move_step_size: 0.03
  move_hold_steps: 0
  # Controlled G1 experiment: grasp realism is off so p/delta/lift are fixed and
  # stiffness/friction effects are not confounded by grasp failure or node jitter.
  grasp_realism: false
measurement:
  fixture_generation_seed: 42
  init_seeds: [0, 1, 2]
  stiffness_multipliers: [0.5, 1.0, 2.0]
  friction_multipliers: [0.5, 1.0, 2.0]
  condition_pairs:
    - [0.5, 1.0]
    - [1.0, 2.0]
    - [0.5, 2.0]
  vel_threshold: 0.001
  settle_max_steps: 5000
  bootstrap_replicates: 5000
  bootstrap_ci: 0.95
  timing_probe:
    enabled: true
    axis: stiffness
    sequence_id: straight_01
    condition: 1.0
    primitive_index: 0
sequences:
  - id: straight_01
    init_shape: straight
    primitives:
